let data = {};

if (mode === 'true' || mode === true) {
  data = $('Mock Input & Context').first().json;
} else {
  data = {
    ingredients: $('Form Trigger').first().json['Ingredients in Fridge'],
    goal: $('Form Trigger').first().json["Today's Goal / Condition"],
    history: "Yesterday: Unknown. Assume needs variety.", // Replace with Google Sheets Read in prod
    sleep_hours: 6
  };
}
return { json: data };

